SELECT  FROM clinic_inventory_log WHERE deleted = 0
AND (business_no LIKE CONCAT('%', #{keyword}, '%') OR business_type LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY id DESC LIMIT #{size} OFFSET #{offset}

